INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('B101: Le email deliverability trinity: authentication (SPF+DKIM+DMARC) + reputation (engagement+complaints) + content (pas de spam words). Les 3 sont necessaires.', 'Deliverability trinity: authentication + reputation + content', 'email', 'best_practice', 0.90, 'batch_101_120', 'system'),
('B102: Le commercial deal stage exit criteria: chaque etape du pipeline a des criteres de sortie. Ex: Demo → Sprint = budget confirme + decision maker identifie + timeline definie.', 'Deal stage exit criteria: budget + DM + timeline pour passer de demo a sprint', 'commercial', 'best_practice', 0.85, 'batch_101_120', 'system'),
('B103: Le content engagement benchmarks par plateforme: IG 1-3% (bon), LI 2-5% (bon), TT 3-8% (bon), X 0.5-1.5% (bon), YT 4-6% (bon).', 'Engagement benchmarks: IG 1-3%, LI 2-5%, TT 3-8%, X 0.5-1.5%, YT 4-6%', 'content', 'insight', 0.85, 'batch_101_120', 'system'),
('B104: Le SEO content decay alert: si un article perd 20%+ de trafic sur 30j, declencher une mise a jour immediate (nouveaux data, sections, mots-cles).', 'SEO content decay: -20% trafic 30j = MAJ immediate', 'seo', 'best_practice', 0.85, 'batch_101_120', 'system'),
('B105: Le ad creative winner identification: apres 1000 impressions, si CTR > 2× moyenne du compte = winner. Allouer 60% du budget dessus.', 'Ad winner: CTR > 2x moyenne apres 1000 imp = winner. 60% budget', 'ads', 'best_practice', 0.85, 'batch_101_120', 'system'),
('B106: Le DM personalization layers: L1=prenom, L2=mention post recent, L3=compliment specifique business, L4=insight industrie, L5=connexion mutuelle. Viser L3+.', 'DM personalization: prenom→post→compliment→insight→connexion. Viser L3+', 'dm_instagram', 'best_practice', 0.85, 'batch_101_120', 'system'),
('B107: Le WhatsApp message template approval: soumettre les templates 48h a l avance. Utiliser des variables {{1}} pour la personnalisation. Eviter les mots promotionnels agressifs.', 'WhatsApp templates: soumettre 48h avant + variables + pas agressif', 'whatsapp', 'best_practice', 0.85, 'batch_101_120', 'system'),
('B108: Le chatbot escalation triggers: mots negatifs (frustre, probleme, rembourser), questions repetees 3x, demande explicite d humain, sentiment score < 0.3.', 'Chatbot escalation: mots negatifs + 3x repete + demande humain + sentiment < 0.3', 'chatbot', 'best_practice', 0.88, 'batch_101_120', 'system'),
('B109: Le GMaps photo strategy: 10 photos/categorie (exterieur, interieur, equipe, produits, ambiance). Les fiches avec 100+ photos ont 520% plus de demandes.', 'GMaps photos: 10/categorie × 5 categories = 50+ photos. 100+ = +520% demandes', 'gmaps', 'best_practice', 0.85, 'batch_101_120', 'system'),
('B110: Le TikTok analytics deep dive: average watch time, traffic source (For You vs Following vs Search), audience demographics, peak hours. Analyser hebdo.', 'TikTok analytics: watch time + source + demographics + peak hours. Hebdo', 'tiktok_comments', 'best_practice', 0.82, 'batch_101_120', 'system'),
('B111: Le CEO quarterly review: 1) resultats vs objectifs, 2) top learnings, 3) agent performance matrix, 4) budget reallocation, 5) next quarter priorities.', 'CEO quarterly: resultats + learnings + agents + budget + priorities', 'ceo', 'best_practice', 0.85, 'batch_101_120', 'system'),
('B112: Le retention health score automation: calculer automatiquement chaque jour. Green > 70, Yellow 40-70, Red < 40. Actions automatiques par zone.', 'Health score auto quotidien: Green>70, Yellow 40-70, Red<40. Actions auto', 'retention', 'best_practice', 0.88, 'batch_101_120', 'system'),
('B113: Le onboarding A/B testing: tester 2 parcours d onboarding differents et mesurer l activation rate. Le gagnant devient le defaut.', 'Onboarding A/B: 2 parcours → mesurer activation → gagnant = defaut', 'onboarding', 'best_practice', 0.82, 'batch_101_120', 'system'),
('B114: Le comptable runway alert system: > 12 mois = vert, 6-12 = jaune, 3-6 = orange, < 3 = rouge. Alerter le CEO a chaque changement de zone.', 'Runway alerts: >12m vert, 6-12 jaune, 3-6 orange, <3 rouge. Alerter CEO', 'comptable', 'best_practice', 0.88, 'batch_101_120', 'system'),
('B115: Le RH hiring velocity: mesurer le temps entre chaque etape (sourcing→screen→interview→offer→accept). Identifier les goulots.', 'Hiring velocity: temps entre etapes. Identifier goulots', 'rh', 'best_practice', 0.80, 'batch_101_120', 'system'),
('B116: Le marketing campaign post-mortem: apres chaque campagne, documenter: objectif, resultats, CAC, learnings, ce qu on referait/pas. Partager avec toute l equipe.', 'Campaign post-mortem: objectif + resultats + CAC + learnings + redo/not', 'marketing', 'best_practice', 0.82, 'batch_101_120', 'system'),
('B117: Le cross-agent deduplication: avant d envoyer un email, verifier si un DM a ete envoye dans les 24h. Avant un DM, verifier si un email est en attente. Eviter le spam multi-canal.', 'Cross-agent dedup: email check DM 24h, DM check email. Eviter spam multi-canal', NULL, 'best_practice', 0.88, 'batch_101_120', 'system'),
('B118: Le customer journey touchpoint mapping: lister CHAQUE interaction (ad vue, site visite, email ouvert, DM recu, demo, trial, achat) et optimiser les transitions.', 'Journey touchpoint mapping: lister chaque interaction + optimiser transitions', NULL, 'best_practice', 0.85, 'batch_101_120', 'system'),
('B119: Le KeiroAI intelligence loop complet: agent execute → resultat mesure → learning stocke (RAG) → agent ameliore → meilleur resultat → nouveau learning. Boucle infinie.', 'KeiroAI loop: execute → mesure → learn RAG → ameliore → meilleur → learn', NULL, 'best_practice', 0.92, 'batch_101_120', 'system'),
('B120: Le KeiroAI competitive moat: chaque client qui utilise KeiroAI enrichit le RAG → meilleurs agents pour tous → plus de clients → plus de data. Effet reseau data.', 'KeiroAI moat: chaque client enrichit RAG → meilleurs agents → plus clients', 'ceo', 'insight', 0.92, 'batch_101_120', 'system'),
('B121: Le email cold outreach mastery: domain warmup 4 sem → 20 emails/jour S1 → 50 S2 → 100 S3 → 200 S4 → max 300. Toujours avec engagement positif (reponses, pas juste envois).', 'Cold outreach: warmup 4 sem, 20→50→100→200→300/jour. Engagement positif', 'email', 'best_practice', 0.85, 'batch_101_120', 'system'),
('B122: Le commercial champion building: identifier LE contact interne qui croit en votre solution. Lui fournir le deck, les chiffres, les objections reponses. Il vend pour vous.', 'Champion building: fournir deck + chiffres + objections reponses. Il vend pour vous', 'commercial', 'best_practice', 0.88, 'batch_101_120', 'system'),
('B123: Le content pillar strategy complete: definir 3-5 piliers (sujets cles) → 10-15 sous-sujets par pilier → calendrier rotatif → jamais a court d idees.', 'Content pillars: 3-5 × 10-15 sous-sujets = calendrier rotatif infini', 'content', 'best_practice', 0.85, 'batch_101_120', 'system'),
('B124: Le SEO keyword prioritization matrix: volume de recherche × keyword difficulty × intent match × business relevance. Score composite = priorite.', 'Keyword prioritization: volume × difficulty × intent × relevance = priorite', 'seo', 'best_practice', 0.85, 'batch_101_120', 'system'),
('B125: Le ad budget optimization weekly: lundi analyser ROAS par campagne, mardi reallouer budget (plus aux gagnantes, moins aux perdantes), vendredi review.', 'Budget optimization hebdo: lundi analyse, mardi reallocation, vendredi review', 'ads', 'best_practice', 0.82, 'batch_101_120', 'system'),
('B126: Le DM follow-up cadence: J0 DM initial → J+3 follow-up leger (value add) → J+7 dernier message (CTA clair) → J+14 like/comment pour rester visible.', 'DM follow-up: J0 initial → J3 value → J7 CTA → J14 engagement', 'dm_instagram', 'best_practice', 0.82, 'batch_101_120', 'system'),
('B127: Le WhatsApp customer journey: prospect recu → message bienvenue (5 min) → qualification (24h) → proposition (48h) → suivi (7j) → relance (14j).', 'WhatsApp journey: bienvenue 5min → qualify 24h → proposition 48h → suivi 7j → relance 14j', 'whatsapp', 'best_practice', 0.82, 'batch_101_120', 'system'),
('B128: Le chatbot knowledge base management: ajouter 5 nouvelles FAQ/semaine basees sur les conversations echouees. En 3 mois, le chatbot couvre 95% des questions.', 'Chatbot KB: +5 FAQ/semaine basees sur echecs. 3 mois = 95% couverture', 'chatbot', 'best_practice', 0.85, 'batch_101_120', 'system'),
('B129: Le GMaps review response timing: repondre dans les 4h aux avis negatifs (empathie + solution) et dans les 24h aux positifs (remerciement + CTA).', 'GMaps response: negatif <4h empathie+solution, positif <24h merci+CTA', 'gmaps', 'best_practice', 0.85, 'batch_101_120', 'system'),
('B130: Le TikTok content repurposing: 1 video longue → 3 clips courts → 5 screenshots avec texte → 1 article blog → 10 tweets/posts. Maximiser chaque creation.', 'TikTok repurposing: 1 video → 3 clips → 5 screenshots → 1 article → 10 posts', 'tiktok_comments', 'best_practice', 0.82, 'batch_101_120', 'system'),
('B131: Le CEO alert priority matrix: P1 (agir immediatement): churn client premium, bug critique, opportunity > 1K MRR. P2 (24h): metriques en baisse, agent erreur.', 'CEO alerts: P1 immediat (churn/bug/big deal), P2 24h (metriques/erreur agent)', 'ceo', 'best_practice', 0.88, 'batch_101_120', 'system'),
('B132: Le retention winback sequence: J+30 post-churn "on a change" → J+60 nouveau case study → J+90 offre speciale retour → J+120 derniere tentative.', 'Winback post-churn: J30 change → J60 case study → J90 offre → J120 dernier', 'retention', 'best_practice', 0.82, 'batch_101_120', 'system'),
('B133: Le onboarding by persona: restaurateur → template food + GMaps + IG food. Coach → template coaching + LinkedIn + webinaire. Ecommerce → template produit + ads + email.', 'Onboarding par persona: restaurant template food, coach template coaching, ecom template produit', 'onboarding', 'best_practice', 0.88, 'batch_101_120', 'system'),
('B134: Le comptable invoice automation: facturation automatique a chaque renouvellement Stripe. Rappel J-7 si paiement a venir. Relance J+3 si echec.', 'Invoice auto: facturation Stripe auto + rappel J-7 + relance J+3 echec', 'comptable', 'best_practice', 0.82, 'batch_101_120', 'system'),
('B135: Le RH 1:1 meeting template: 5 questions fixes: comment ca va? qu as-tu accompli? qu est-ce qui te bloque? comment je peux t aider? feedback pour moi?', 'RH 1:1 template: 5 questions (ca va? accompli? bloque? aide? feedback?)', 'rh', 'best_practice', 0.80, 'batch_101_120', 'system'),
('B136: Le marketing A/B test calendar: mois 1 emails subjects, mois 2 landing pages headlines, mois 3 ad creatives, mois 4 CTA buttons, mois 5 pricing page, mois 6 onboarding flow.', 'A/B test calendar: M1 subjects, M2 headlines, M3 creatives, M4 CTAs, M5 pricing, M6 onboarding', 'marketing', 'best_practice', 0.82, 'batch_101_120', 'system'),
('B137: Le inter-agent insight sharing protocol: lundi matin, chaque agent publie son top insight de la semaine dans le shared context. Le CEO redistribue.', 'Insight sharing lundi: chaque agent → top insight → CEO redistribue', NULL, 'best_practice', 0.85, 'batch_101_120', 'system'),
('B138: Le customer segmentation by value: whales (top 10% revenue) → high-touch. Mid-tier (next 30%) → tech-touch. Long tail (bottom 60%) → self-serve.', 'Segmentation valeur: whales high-touch, mid tech-touch, long-tail self-serve', NULL, 'best_practice', 0.85, 'batch_101_120', 'system'),
('B139: Le product usage analytics: feature adoption heatmap (quelles features sont utilisees par quels segments) = guide le roadmap produit.', 'Feature adoption heatmap par segment = guide roadmap produit', 'ceo', 'best_practice', 0.82, 'batch_101_120', 'system'),
('B140: Le KeiroAI agent autonomy levels: L1 suggestion (propose), L2 draft (prepare), L3 semi-auto (execute avec approbation), L4 auto (execute seul), L5 strategique (decide + execute).', 'Agent autonomy: L1 suggest, L2 draft, L3 semi-auto, L4 auto, L5 strategique', 'ceo', 'best_practice', 0.90, 'batch_101_120', 'system'),
('B141: Le email reply handling framework: positif → CRM update hot + proposer RDV. Neutre → repondre question + CTA soft. Negatif → desinscrire + noter raison. Spam → ignorer.', 'Email reply: positif→RDV, neutre→repondre+CTA, negatif→desinscrire, spam→ignorer', 'email', 'best_practice', 0.85, 'batch_101_120', 'system'),
('B142: Le commercial discovery questions elite: quel est votre plus gros defi? combien ca vous coute? qu avez-vous essaye? quel serait le resultat ideal? quelle est votre timeline?', 'Discovery 5 questions: defi? cout? essaye? ideal? timeline?', 'commercial', 'best_practice', 0.88, 'batch_101_120', 'system'),
('B143: Le content performance analysis weekly: top 3 posts (pourquoi ils ont marche) + bottom 3 (pourquoi ils ont echoue) + 3 actions pour la semaine prochaine.', 'Content analysis hebdo: top 3 + bottom 3 + 3 actions semaine+1', 'content', 'best_practice', 0.85, 'batch_101_120', 'system'),
('B144: Le SEO backlink monitoring: tracker les nouveaux backlinks/semaine + les backlinks perdus. Si un backlink important est perdu, contacter le site pour le recuperer.', 'Backlink monitoring: nouveaux + perdus/semaine. Perdus importants = contacter', 'seo', 'best_practice', 0.82, 'batch_101_120', 'system'),
('B145: Le ad fatigue early detection: si le CTR baisse de 20% sur 3 jours consecutifs avec la meme audience, c est de la fatigue. Renouveler la creative.', 'Ad fatigue: CTR -20% 3j consecutifs = fatigue. Renouveler creative', 'ads', 'insight', 0.85, 'batch_101_120', 'system'),
('B146: Le DM Instagram safe zone limits: max 30 nouveaux DMs/jour, max 10 follows/heure, max 50 likes/heure. Au-dela = risque restriction IG.', 'DM safe zone: 30 DMs/jour, 10 follows/h, 50 likes/h. Au-dela = restriction', 'dm_instagram', 'best_practice', 0.88, 'batch_101_120', 'system'),
('B147: Le WhatsApp quality rating: Meta note la qualite des messages (Green/Yellow/Red). Yellow = ralentir. Red = bloquer pendant 7 jours. Surveiller quotidiennement.', 'WhatsApp quality: Green ok, Yellow ralentir, Red bloque 7j. Surveiller quotidien', 'whatsapp', 'best_practice', 0.85, 'batch_101_120', 'system'),
('B148: Le chatbot conversation design patterns: greeting → understand intent → confirm → act → verify → close. 6 etapes pour chaque conversation.', 'Chatbot design: greeting → understand → confirm → act → verify → close', 'chatbot', 'best_practice', 0.85, 'batch_101_120', 'system'),
('B149: Le GMaps competitor analysis: comparer note, nombre d avis, frequence de posts, photos, reponses aux avis avec les 5 concurrents locaux. Etre meilleur sur chaque metrique.', 'GMaps competitor: comparer note/avis/posts/photos/reponses avec 5 concurrents locaux', 'gmaps', 'best_practice', 0.82, 'batch_101_120', 'system'),
('B150: Le TikTok trending sound detection: utiliser la Creative Center TikTok pour identifier les sons en croissance. Les utiliser dans les 24-48h = max portee.', 'TikTok trending: Creative Center → sons en croissance → utiliser 24-48h', 'tiktok_comments', 'best_practice', 0.82, 'batch_101_120', 'system')
